# Math utilities module with functions and classes
import geometric_shapes

@static
class MathUtils:
    PI: float = 3.14159

    @static
    def sum(numbers: list[float]) -> float:
        total: float = 0.0
        for n in numbers:
            total += n
        return total

    @static
    def average(numbers: list[float]) -> float:
        if len(numbers) == 0:
            return 0.0
        return MathUtils.sum(numbers) / len(numbers)

class Statistics:
    values: list[float]

    def __init__(self):
        self.values = []

    def add(self, value: float) -> None:
        self.values.append(value)

    def mean(self) -> float:
        return MathUtils.average(self.values)

    def max_val(self) -> float:
        if len(self.values) == 0:
            return 0.0
        result: float = self.values[0]
        for v in self.values:
            if v > result:
                result = v
        return result

    def min_val(self) -> float:
        if len(self.values) == 0:
            return 0.0
        result: float = self.values[0]
        for v in self.values:
            if v < result:
                result = v
        return result

